from dataclasses import dataclass

@dataclass
class CorpusDocument:
    url: str
    text: str
    source: str          # e.g. "common_crawl", "github", "wikipedia"
    language: str        # ISO 639-1
    token_count: int
    quality_score: float  # 0.0–1.0 (heuristic)
    licence: str | None   # SPDX or None if unknown
    opted_out: bool       # True if robots.txt / registry says exclude

def should_include(doc: CorpusDocument,
                   min_quality: float = 0.6,
                   allowed_languages: set[str] | None = None) -> bool:
    if doc.opted_out:
        return False
    if doc.quality_score < min_quality:
        return False
    if doc.licence in ("CC-BY-NC-4.0", "CC-BY-NC-SA-4.0"):
        return False   # non-commercial — exclude from commercial training
    if allowed_languages and doc.language not in allowed_languages:
        return False
    return True

from dataclasses import dataclass
from enum import Enum

class QualityFlag(Enum):
    PASS         = "pass"
    FAIL_PII     = "fail_pii"
    FAIL_HARMFUL = "fail_harmful"
    FAIL_FORMAT  = "fail_format"
    FAIL_SHORT   = "fail_short"
    NEEDS_REVIEW = "needs_review"

@dataclass
class FineTuningExample:
    id: str
    instruction: str
    response: str
    source: str
    labeller_id: str | None = None

    def quality_flag(self) -> QualityFlag:
        import re
        # PII check
        if re.search(r'\b\d{3}-\d{2}-\d{4}\b', self.response):   # SSN pattern
            return QualityFlag.FAIL_PII
        if re.search(r'[a-zA-Z0-9._%+\-]+@[a-zA-Z0-9.\-]+\.[a-z]{2,}', self.response):
            return QualityFlag.FAIL_PII
        # Length check
        if len(self.response.split()) < 5:
            return QualityFlag.FAIL_SHORT
        # Harmful content heuristic
        harmful_phrases = ["how to make a bomb", "synthesise fentanyl"]
        if any(ph in self.instruction.lower() for ph in harmful_phrases):
            return QualityFlag.FAIL_HARMFUL
        return QualityFlag.PASS

def filter_dataset(examples: list[FineTuningExample]) -> dict:
    passed, rejected = [], []
    for ex in examples:
        flag = ex.quality_flag()
        if flag == QualityFlag.PASS:
            passed.append(ex)
        else:
            rejected.append((ex.id, flag.value))
    return {"passed": passed, "rejected": rejected,
            "pass_rate": len(passed) / len(examples) if examples else 0}
